config.script:
results = []
for cert in loop_1.renewal_results:
    if cert.status == 'success':
        check = integration.execute('cert_manager', 'verify_ssl', { 'domain': cert.domain, 'expected_expiry_after': '13d' })
        results.append({ 'domain': cert.domain, 'verified': check.valid })
result = results

notify.message:
SSL CERTIFICATE RENEWALS COMPLETE
Time: {{trigger_1.timestamp}}
Renewed: {{loop_1.renewal_results | filter(status == 'success') | length}} certificates

Domains:
{{loop_1.renewal_results | filter(status == 'success') | map(domain + ' — Verified: ' + verified)}}

All certificates deployed and services reloaded.

parameters.description:
Automated SSL renewal failed for the following certificates:

{{loop_1.renewal_results | filter(status != 'success') | map(domain + ' — Error: ' + error_message)}}

Manual renewal and deployment required before expiry.

notify.message:
SSL RENEWAL FAILURES — URGENT
Failed Certificates:
{{loop_1.renewal_results | filter(status != 'success') | map(domain + ' — ' + error_message)}}

Ticket: {{respond_3.issue_key}}

Manual intervention required before these certificates expire.
